function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    const maxNum = 1000000;
    const spf = new Array(maxNum + 1).fill(0);

    for (let i = 2; i <= maxNum; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= maxNum; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    const primeIndices = new Map();

    for (let j = 0; j < n; j++) {
        const x = nums[j];
        if (x === 1) continue;
        let temp = x;
        const factors = new Set();
        while (temp > 1) {
            const p = spf[temp];
            factors.add(p);
            while (temp % p === 0) {
                temp /= p;
            }
        }
        for (const p of factors) {
            if (!primeIndices.has(p)) {
                primeIndices.set(p, []);
            }
            primeIndices.get(p).push(j);
        }
    }

    const visited = new Array(n).fill(false);
    const queue = [{ index: 0, steps: 0 }];
    visited[0] = true;

    while (queue.length > 0) {
        const { index, steps } = queue.shift();
        if (index === n - 1) {
            return steps;
        }

        const nextIndices = [];
        if (index > 0) nextIndices.push(index - 1);
        if (index < n - 1) nextIndices.push(index + 1);

        for (const next of nextIndices) {
            if (!visited[next]) {
                visited[next] = true;
                queue.push({ index: next, steps: steps + 1 });
            }
        }

        const currentNum = nums[index];
        if (currentNum === 1) continue;
        const p = spf[currentNum];
        if (p === currentNum) {
